export function applyScoreChange(
  state: IntimacyState,
  interaction: IntimacyInteraction,
): IntimacyState {
  const delta = INTIMACY_SCORE_CHANGES[interaction]
  const newScore = Math.min(100, state.score + delta)
  return { score: newScore, stage: getStageForScore(newScore) }
}

export interface TriggerCondition {
  id: string
  name: string
  check: (input: TriggerInput) => boolean
  cooldownMs: number
}

describe('applyScoreChange', () => {
  it('clamps score at 100', () => {
    const state = createIntimacyState(99)
    const next = applyScoreChange(state, 'deepConversation')
    expect(next.score).toBe(100)
  })
})

export interface IntimacyState {
  readonly score: number
  readonly stage: IntimacyStage
}

findings.suggestion:
Current approach with factory functions is pragmatic. For stronger enforcement, consider an opaque/branded type:

type ValidatedIntimacyState = IntimacyState & { readonly __brand: 'ValidatedIntimacyState' }

This would ensure only factory-produced values are accepted. Low priority -- current pattern is adequate for the domain.

